// @n8n-evol-I:primitive — exempt from pure-function discipline
// Build the Upstash REST command body for XADD. Payload is JSON.stringify'd
// into a single 'payload' field — Streams require flat string field/value pairs.
// Caller-supplied max_len becomes 'MAXLEN ~ <n>' (approximate trimming, much
// cheaper than exact). approximate=false uses 'MAXLEN <n>' (exact).
const stream = $json.stream;
if (!stream || typeof stream !== 'string') {
  throw new Error("queue_publish: 'stream' is required and must be a string");
}
const payload = typeof $json.payload === 'string' ? $json.payload : JSON.stringify($json.payload || {});
const maxLen = (typeof $json.max_len === 'number' && $json.max_len > 0) ? $json.max_len : null;
const approximate = $json.approximate !== false;
const cmd = ['XADD', stream];
if (maxLen !== null) {
  cmd.push('MAXLEN');
  if (approximate) cmd.push('~');
  cmd.push(String(maxLen));
}
cmd.push('*', 'payload', payload, 'enqueued_at', new Date().toISOString());
return [{ json: { stream, cmd, payload_str: payload } }];

// @n8n-evol-I:primitive — exempt from pure-function discipline
const ctx = $('Build Publish Context').first().json;
const resp = $json;
if (resp && resp.error) {
  throw new Error(`queue_publish XADD failed for stream='${ctx.stream}': ${resp.error}`);
}
const messageId = resp ? resp.result : null;
return [{ json: { stream: ctx.stream, message_id: messageId, published: true } }];
